package main

import (
    "html/template"
    "log"
    "net/http"
    "time"
)

// AnalyticsData represents the data structure for search analytics
type AnalyticsData struct {
    Keyword     string    `json:"keyword"`
    Timestamp   time.Time `json:"timestamp"`
    UserAgent   string    `json:"user_agent"`
    RemoteAddr  string    `json:"remote_addr"`
}

// searchResultsTemplate defines the HTML template for search results
const searchResultsTemplate = `
<!DOCTYPE html>
<html>
<head>
    <meta charset="UTF-8">
    <title>Product Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .container { max-width: 800px; margin: 0 auto; }
        .keyword { color: #2c3e50; }
        .analytics { margin-top: 30px; padding: 15px; background: #f8f9fa; border-left: 4px solid #3498db; }
        .timestamp { color: #7f8c8d; font-size: 0.9em; }
    </style>
</head>
<body>
    <div class="container">
        <h2>Search Results: <span class="keyword">{{.Keyword}}</span></h2>
        {{if .Results}}
            <ul>
            {{range .Results}}
                <li><strong>{{.Name}}</strong> - ${{.Price}} ({{.Category}})</li>
            {{end}}
            </ul>
        {{else}}
            <p>No products found for "{{.Keyword}}".</p>
        {{end}}

        <div class="analytics">
            <h3>Search Analytics</h3>
            <p>Search performed at: <span class="timestamp">{{.Analytics.Timestamp.Format "2006-01-02 15:04:05"}}</span></p>
            <p>Client IP: {{.Analytics.RemoteAddr}}</p>
        </div>
    </div>
</body>
</html>
`

// Product represents a product in search results
type Product struct {
    Name     string  `json:"name"`
    Price    float64 `json:"price"`
    Category string  `json:"category"`
}

// SearchData holds all data needed for the template
type SearchData struct {
    Keyword   string
    Results   []Product
    Analytics AnalyticsData
}

// HandleProductSearch handles product search requests with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Set content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Parse query parameter
    query := r.URL.Query()
    keyword := query.Get("keyword")

    // Default keyword if not provided
    if keyword == "" {
        keyword = "all products"
    }

    // Collect analytics data
    analytics := AnalyticsData{
        Keyword:    keyword,
        Timestamp:  time.Now(),
        UserAgent:  r.UserAgent(),
        RemoteAddr: r.RemoteAddr,
    }

    // Log analytics (in production, this would go to a database or analytics service)
    log.Printf("SEARCH_ANALYTICS: keyword=%q, timestamp=%s, user_agent=%q, remote_addr=%q",
        analytics.Keyword,
        analytics.Timestamp.Format(time.RFC3339),
        analytics.UserAgent,
        analytics.RemoteAddr)

    // Simulate product search results
    results := simulateProductSearch(keyword)

    // Prepare template data
    data := SearchData{
        Keyword:   keyword,
        Results:   results,
        Analytics: analytics,
    }

    // Parse and execute template
    tmpl, err := template.New("searchResults").Parse(searchResultsTemplate)
    if err != nil {
        http.Error(w, "Error processing template: "+err.Error(), http.StatusInternalServerError)
        return
    }

    // Execute template with data
    if err := tmpl.Execute(w, data); err != nil {
        http.Error(w, "Error rendering page: "+err.Error(), http.StatusInternalServerError)
    }
}

// simulateProductSearch returns mock product data based on keyword
func simulateProductSearch(keyword string) []Product {
    // Mock product database
    allProducts := []Product{
        {"Laptop", 999.99, "Electronics"},
        {"Smartphone", 699.99, "Electronics"},
        {"Coffee Maker", 89.99, "Home Appliances"},
        {"Running Shoes", 129.99, "Sports"},
        {"Desk Chair", 199.99, "Furniture"},
        {"Book: Go Programming", 39.99, "Books"},
        {"Headphones", 149.99, "Electronics"},
        {"Yoga Mat", 29.99, "Sports"},
    }

    // Filter products based on keyword (case-insensitive)
    var results []Product
    keywordLower := strings.ToLower(keyword)

    for _, product := range allProducts {
        if keywordLower == "all" || keywordLower == "all products" {
            results = allProducts
            break
        }

        if strings.Contains(strings.ToLower(product.Name), keywordLower) ||
            strings.Contains(strings.ToLower(product.Category), keywordLower) {
            results = append(results, product)
        }
    }

    return results
}

func main() {
    // Register the handler
    http.HandleFunc("/search", HandleProductSearch)

    // Default route with instructions
    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
