package main

import (
    "fmt"
    "html"
    "log"
    "net/http"
    "time"
)

// HandleProductSearch handles product search requests and logs analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    startTime := time.Now()

    // Set content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Parse query parameters
    query := r.URL.Query()
    keyword := query.Get("keyword")

    // Log analytics data
    logAnalytics(r, keyword, startTime)

    // Generate HTML response
    htmlResponse := generateHTML(keyword)

    // Write response
    fmt.Fprint(w, htmlResponse)
}

// logAnalytics logs search analytics information
func logAnalytics(r *http.Request, keyword string, startTime time.Time) {
    duration := time.Since(startTime)

    logData := map[string]interface{}{
        "timestamp":    startTime.Format(time.RFC3339),
        "method":       r.Method,
        "path":         r.URL.Path,
        "query":        r.URL.RawQuery,
        "remote_addr":  r.RemoteAddr,
        "user_agent":   r.UserAgent(),
        "keyword":      keyword,
        "keyword_len":  len(keyword),
        "processing_ms": duration.Milliseconds(),
    }

    // Convert to JSON-like log format
    log.Printf("SEARCH_ANALYTICS: timestamp=%s method=%s path=%s query=%s remote_addr=%s user_agent=%s keyword=%s keyword_len=%d processing_ms=%d",
        logData["timestamp"],
        logData["method"],
        logData["path"],
        logData["query"],
        logData["remote_addr"],
        logData["user_agent"],
        logData["keyword"],
        logData["keyword_len"],
        logData["processing_ms"],
    )
}

// generateHTML creates the HTML response with search results
func generateHTML(keyword string) string {
    // Escape the keyword to prevent XSS attacks
    escapedKeyword := html.EscapeString(keyword)

    // If keyword is empty, provide a default message
    if escapedKeyword == "" {
        escapedKeyword = "No keyword provided"
    }

    htmlTemplate := `<!DOCTYPE html>
<html lang="en">
<head>
