// HandleProductSearch processes product search requests
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse query parameters
	query := r.URL.Query()
	keyword := query.Get("keyword")

	// Prepare template data
	data := TemplateData{}

	// Validate keyword
	if keyword == "" {
		data.Error = "Please provide a search keyword using the 'keyword' query parameter."
		renderTemplate(w, data)
		return
	}

	// Decode URL-encoded keyword
	decodedKeyword, err := url.QueryUnescape(keyword)
	if err != nil {
		decodedKeyword = keyword // Fallback to original if decoding fails
	}

	// Update analytics
	analytics := updateAnalytics(decodedKeyword, r)

	// Set data for template
	data.Keyword = decodedKeyword
	data.Analytics = analytics
	data.Products = searchProducts(decodedKeyword)

	// Render the template
	renderTemplate(w, data)
}

// updateAnalytics tracks search metrics
func updateAnalytics(keyword string, r *http.Request) *SearchAnalytics {
	// Get or create analytics entry
	analytics, exists := searchAnalytics[keyword]
	if !exists {
		analytics = &SearchAnalytics{
			Keyword:     keyword,
			Timestamp:   time.Now(),
			UserAgent:   r.UserAgent(),
			RemoteAddr:  r.RemoteAddr,
			SearchCount: 0,
		}
		searchAnalytics[keyword] = analytics
	}

