		{"Smartphone", 699.99, "Latest smartphone with 128GB storage and triple camera"},
		{"Laptop", 1299.99, "15-inch laptop with 16GB RAM and 512GB SSD"},
		{"Smart Watch", 249.99, "Fitness tracker with heart rate monitor and GPS"},
		{"Tablet", 399.99, "10-inch tablet with stylus support"},
		{"Gaming Console", 499.99, "Next-gen gaming console with 1TB storage"},
		{"Digital Camera", 899.99, "Mirrorless camera with 4K video recording"},
		{"Bluetooth Speaker", 79.99, "Portable waterproof speaker with 360° sound"},
	}

	// Simple keyword matching (case-insensitive)
	var results []Product
	lowerKeyword := toLower(keyword)

	for _, product := range allProducts {
		if contains(toLower(product.Name), lowerKeyword) || 
		   contains(toLower(product.Description), lowerKeyword) {
			results = append(results, product)
		}
	}

	return results
}

// Helper functions for case-insensitive search
func toLower(s string) string {
	// Simple ASCII lowercase conversion
	// For production use strings.ToLower() with proper Unicode handling
	bytes := []byte(s)
	for i, b := range bytes {
		if b >= 'A' && b <= 'Z' {
			bytes[i] = b + 32
		}
	}
	return string(bytes)
}

func contains(s, substr string) bool {
	// Simple substring check
	// For production use strings.Contains()
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

