}

func main() {
	// Register handlers
	http.HandleFunc("/", HandleRoot)
	http.HandleFunc("/search", HandleProductSearch)

	// Start server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s", port)
	log.Println("Try visiting: http://localhost:8080/search?keyword=wireless")

