package main

import (
	"html/template"
	"log"
	"net/http"
	"time"
)

// SearchAnalytics represents analytics data for a search
type SearchAnalytics struct {
	Keyword    string    `json:"keyword"`
	Timestamp  time.Time `json:"timestamp"`
	UserAgent  string    `json:"user_agent"`
	RemoteAddr string    `json:"remote_addr"`
}

// HandleProductSearch handles product search requests with analytics
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse query parameter
	keyword := r.URL.Query().Get("keyword")
	if keyword == "" {
		keyword = "No keyword provided"
	}

	// Record analytics
	recordSearchAnalytics(r, keyword)

	// Create HTML template
	tmpl := `<!DOCTYPE html>
<html>
<head>
    <title>Product Search Results</title>
    <style>
        body { font-family: Arial, sans-serif; margin: 40px; }
        .container { max-width: 800px; margin: 0 auto; }
        .results { margin-top: 20px; padding: 15px; border: 1px solid #ddd; }
        .analytics { margin-top: 30px; font-size: 14px; color: #666; }
        .product { padding: 10px; border-bottom: 1px solid #eee; }
        .product:last-child { border-bottom: none; }
    </style>
</head>
<body>
    <div class="container">
        <h2>Search Results: {{.Keyword}}</h2>

        <div class="results">
            {{if .Products}}
                {{range .Products}}
                <div class="product">
                    <h3>{{.Name}}</h3>
                    <p>{{.Description}}</p>
                    <p><strong>Price:</strong> ${{.Price}}</p>
                </div>
                {{end}}
            {{else}}
                <p>No products found for "{{.Keyword}}"</p>
            {{end}}
        </div>

        <div class="analytics">
            <p>Search performed at: {{.Timestamp.Format "2006-01-02 15:04:05"}}</p>
        </div>
    </div>
</body>
</html>`

	// Sample product data (in real app, this would come from a database)
	products := []struct {
		Name        string
		Description string
		Price       float64
	}{
		{"Wireless Headphones", "Noise-cancelling over-ear headphones", 199.99},
		{"Smart Watch", "Fitness tracker with heart rate monitor", 299.99},
		{"Laptop Stand", "Adjustable aluminum laptop stand", 49.99},
	}

	// Prepare template data
	data := struct {
		Keyword   string
		Products  []struct {
			Name        string
			Description string
			Price       float64
		}
		Timestamp time.Time
	}{
		Keyword:   keyword,
		Products:  products,
		Timestamp: time.Now(),
	}

	// Parse and execute template
	t, err := template.New("search").Parse(tmpl)
	if err != nil {
		http.Error(w, "Error generating page", http.StatusInternalServerError)
		log.Printf("Template error: %v", err)
		return
	}

	// Execute template
	if err := t.Execute(w, data); err != nil {
		http.Error(w, "Error rendering page", http.StatusInternalServerError)
		log.Printf("Template execution error: %v", err)
	}
}

// recordSearchAnalytics logs search analytics data
func recordSearchAnalytics(r *http.Request, keyword string) {
	analytics := SearchAnalytics{
		Keyword:    keyword,
		Timestamp:  time.Now(),
		UserAgent:  r.UserAgent(),
		RemoteAddr: r.RemoteAddr,
	}

	// Log analytics (in production, this would be stored in a database)
	log.Printf("Search Analytics: Keyword=%q, Time=%s, UserAgent=%q, IP=%s",
		analytics.Keyword,
		analytics.Timestamp.Format(time.RFC3339),
		analytics.UserAgent,
		analytics.RemoteAddr,
	)
}

func main() {
	// Register handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start server
	port := ":8080"
	log.Printf("Server starting on http://localhost%s", port)
	log.Printf("Try: http://localhost%s/search?keyword=laptop", port)

	if err := http.ListenAndServe(port, nil); err != nil {
		log.Fatal("Server error:", err)
	}
}

