// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    startTime := time.Now()

    // Set response content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Parse query parameters
    query := r.URL.Query()
    keyword := query.Get("keyword")

    // Analytics: log search details
    log.Printf("Product search: keyword=%q, user_agent=%q, remote_addr=%s",
        keyword, r.UserAgent(), r.RemoteAddr)

    // Build HTML response
    htmlContent := buildSearchPage(keyword)

    // Write response
    fmt.Fprint(w, htmlContent)

    // Analytics: log request processing time
    duration := time.Since(startTime)
    log.Printf("Search request processed in %v", duration)
}

// buildSearchPage generates the HTML page with search results
func buildSearchPage(keyword string) string {
    escapedKeyword := html.EscapeString(keyword)

    htmlOutput := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <style>
        body {
