package main

import (
	"html/template"
	"net/http"
)

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set default value if keyword is empty
	if keyword == "" {
		keyword = "All Products"
	}

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML template
	htmlTemplate := `<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results - {{.Keyword}}</title>
</head>
<body>
    <header>
        <h1>Product Search Results</h1>
    </header>
    <main>
        <h2>Search Results: {{.Keyword}}</h2>
        <!-- Analytics tracking would be implemented here -->
        <div id="analytics-data" data-search-keyword="{{.Keyword}}"></div>
    </main>
</body>
</html>`

	// Create template and execute with data
	tmpl, err := template.New("searchResults").Parse(htmlTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Data for template
	data := struct {
		Keyword string
	}{
		Keyword: keyword,
	}

	// Execute template
	if err := tmpl.Execute(w, data); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

