            <strong>Analytics Note:</strong> This search has been logged for product improvement purposes.
            <br>Timestamp: %s | User Agent: %s
        </div>
    </div>
</body>
</html>`, safeKeyword, safeKeyword, analytics.Timestamp.Format("2006-01-02 15:04:05"), html.EscapeString(analytics.UserAgent))

    // Write HTML response
    w.WriteHeader(http.StatusOK)
    w.Write([]byte(htmlContent))
}

// logAnalytics logs search analytics to console
func logAnalytics(analytics SearchAnalytics) {
    // Convert to JSON for structured logging
    jsonData, err := json.MarshalIndent(analytics, "", "  ")
    if err != nil {
        fmt.Printf("Error marshaling analytics: %v\n", err)
        return
    }

    fmt.Printf("SEARCH ANALYTICS:\n%s\n\n", string(jsonData))
}

func main() {
    // Register the handler
    http.HandleFunc("/search", HandleProductSearch)

    // Root handler redirects to search with example keyword
    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
        http.Redirect(w, r, "/search?keyword=electronics", http.StatusFound)
    })

    // Start the server
    fmt.Println("Server starting on http://localhost:8080")
    fmt.Println("Try visiting: http://localhost:8080/search?keyword=laptop")
    fmt.Println("Or: http://localhost:8080/search?keyword=wireless%20headphones")

    if err := http.ListenAndServe(":8080", nil); err != nil {
        fmt.Printf("Server error: %v\n", err)
    }
}

