// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse search keyword from query parameters
	keyword := r.URL.Query().Get("keyword")

	// Log analytics data
	logAnalytics(r, keyword)

	// Build HTML response
	htmlResponse := buildHTMLResponse(keyword)

	// Write response
	w.Write([]byte(htmlResponse))
}

// logAnalytics logs search analytics data
func logAnalytics(r *http.Request, keyword string) {
	// Collect analytics data
	analyticsData := struct {
		Timestamp  time.Time `json:"timestamp"`
		Keyword    string    `json:"keyword"`
		UserAgent  string    `json:"user_agent"`
		RemoteAddr string    `json:"remote_addr"`
		Method     string    `json:"method"`
		URL        string    `json:"url"`
	}{
		Timestamp:  time.Now().UTC(),
		Keyword:    keyword,
		UserAgent:  r.UserAgent(),
		RemoteAddr: r.RemoteAddr,
		Method:     r.Method,
		URL:        r.URL.String(),
	}

	// Log analytics data in structured format
	log.Printf("PRODUCT_SEARCH_ANALYTICS: keyword=%q user_agent=%q remote_addr=%q method=%q url=%q",
		analyticsData.Keyword,
		analyticsData.UserAgent,
		analyticsData.RemoteAddr,
		analyticsData.Method,
		analyticsData.URL,
	)
}

