package main

import (
	"html"
	"log"
	"net/http"
	"time"
)

// AnalyticsEntry represents a single search analytics record
type AnalyticsEntry struct {
	Timestamp time.Time `json:"timestamp"`
	Keyword   string    `json:"keyword"`
	IPAddress string    `json:"ip_address"`
	UserAgent string    `json:"user_agent"`
}

// AnalyticsStore holds search analytics data in memory
type AnalyticsStore struct {
	entries []AnalyticsEntry
}

// RecordSearch logs a search event for analytics
func (as *AnalyticsStore) RecordSearch(keyword, ip, userAgent string) {
	entry := AnalyticsEntry{
		Timestamp: time.Now(),
		Keyword:   keyword,
		IPAddress: ip,
		UserAgent: userAgent,
	}
	as.entries = append(as.entries, entry)

	// Log to console for monitoring
	log.Printf("Search recorded: %s from %s", keyword, ip)
}

// GetAnalytics returns all recorded search entries
func (as *AnalyticsStore) GetAnalytics() []AnalyticsEntry {
	return as.entries
}

// Global analytics store instance
var analyticsStore = &AnalyticsStore{}

// HandleProductSearch handles product search requests with analytics support
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse query parameter
	keyword := r.URL.Query().Get("keyword")

	// Record analytics
	ipAddress := r.RemoteAddr
	if forwarded := r.Header.Get("X-Forwarded-For"); forwarded != "" {
		ipAddress = forwarded
	}
	userAgent := r.Header.Get("User-Agent")

	analyticsStore.RecordSearch(keyword, ipAddress, userAgent)

	// Generate HTML response
	htmlContent := `<!DOCTYPE html>
<html>
<head>
    <title>Product Search Results</title>
    <style>
        body {
            font-family: Arial, sans-serif;
            margin: 40px;
            line-height: 1.6;
        }
        .container {
            max-width: 800px;
            margin: 0 auto;
            padding: 20px;
            border: 1px solid #ddd;
            border-radius: 5px;
            background-color: #f9f9f9;
        }
        h2 {
            color: #333;
            border-bottom: 2px solid #4CAF50;
            padding-bottom: 10px;
        }
        .search-info {
            background-color: #e8f5e9;
            padding: 15px;
            border-radius: 4px;
            margin: 20px 0;
        }
        .analytics-info {
            font-size: 0.9em;
            color: #666;
            margin-top: 30px;
            padding-top: 15px;
            border-top: 1px solid #ddd;
        }
        .keyword {
            color: #4CAF50;
            font-weight: bold;
        }
    </style>
</head>
<body>
    <div class="container">
        <h2>Search Results: ` + html.EscapeString(keyword) + `</h2>

        <div class="search-info">
            <p>Search keyword: <span class="keyword">"` + html.EscapeString(keyword) + `"</span></p>
            <p>Your search has been recorded for analytics purposes.</p>
        </div>

        <div class="analytics-info">
            <p>Total searches recorded: ` + html.EscapeString(string(rune(len(analyticsStore.GetAnalytics())))) + `</p>
            <p>This page uses standard Go libraries for analytics tracking.</p>
        </div>
    </div>
</body>
</html>`

	// Write HTML response
	w.Write([]byte(htmlContent))
}

func main() {
	// Register handler
	http.HandleFunc("/search", HandleProductSearch)

	// Start server
	log.Println("Server starting on :8080")
	log.Println("Access the search page at: http://localhost:8080/search?keyword=your_search_term")
	log.Fatal(http.ListenAndServe(":8080", nil))
}

