package main

import (
	"html/template"
	"net/http"
)

// Template for the search results page
const searchResultsTemplate = `<!DOCTYPE html>
<html>
<head>
    <title>Product Search Results</title>
</head>
<body>
    <h2>Search Results: {{.Keyword}}</h2>
</body>
</html>`

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse and execute the template with safe HTML escaping
	tmpl, err := template.New("searchResults").Parse(searchResultsTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Data to pass to template
	data := struct {
		Keyword string
	}{
		Keyword: keyword,
	}

	// Execute template with safe escaping
	if err := tmpl.Execute(w, data); err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
	}
}

