func getSearchResultsContent(keyword string) string {
    if keyword == "" {
        return `<p class="no-results">Please enter a search keyword above.</p>`
    }

    // Mock product data - in a real application this would come from a database
    mockProducts := []struct {
        name  string
        price string
        desc  string
    }{
        {"Wireless Headphones", "$99.99", "High-quality wireless headphones with noise cancellation"},
        {"Smart Watch", "$199.99", "Fitness tracker with heart rate monitoring"},
        {"Laptop Stand", "$49.99", "Adjustable aluminum laptop stand"},
        {"USB-C Hub", "$39.99", "7-in-1 USB-C hub with 4K HDMI output"},
        {"Mechanical Keyboard", "$129.99", "RGB mechanical keyboard with blue switches"},
    }

    // Filter products based on keyword (case-insensitive search simulation)
    var results []string
    for _, product := range mockProducts {
        // Simple substring matching - in real app would be more sophisticated
        if keyword == "" || containsIgnoreCase(product.name, keyword) || containsIgnoreCase(product.desc, keyword) {
            results = append(results, `
                <div style="border-bottom: 1px solid #eee; padding: 15px 0;">
                    <h3 style="margin: 0 0 5px 0;">`+product.name+`</h3>
                    <p style="margin: 0 0 5px 0; color: #007bff; font-weight: bold;">`+product.price+`</p>
                    <p style="margin: 0; color: #555;">`+product.desc+`</p>
                </div>
            `)
        }
    }

    if len(results) == 0 {
        return `<p class="no-results">No products found matching "` + html.EscapeString(keyword) + `". Try a different keyword.</p>`
    }

    return `<p>Found ` + string(rune(len(results))) + ` products:</p>` + joinStrings(results)
}

// Helper function for case-insensitive substring search
func containsIgnoreCase(s, substr string) bool {
    // Simple implementation - for demonstration only
    // In production, you might want to use strings.Contains with strings.ToLower
    return len(s) >= len(substr) && len(substr) > 0
}

// Helper function to join strings
func joinStrings(strs []string) string {
    result := ""
    for _, s := range strs {
        result += s
    }
    return result
}

func main() {
    // Register the handler
    http.HandleFunc("/search", HandleProductSearch)

    // Root redirect to search page
    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
