// SearchAnalytics tracks search keyword usage
type SearchAnalytics struct {
    mu       sync.RWMutex
    keywords map[string]int
    history  []SearchEvent
}

// SearchEvent represents a single search event
type SearchEvent struct {
    Keyword   string    `json:"keyword"`
    Timestamp time.Time `json:"timestamp"`
    IPAddress string    `json:"ip_address,omitempty"`
}

var analytics = &SearchAnalytics{
    keywords: make(map[string]int),
    history:  make([]SearchEvent, 0),
}

// HandleProductSearch processes product search requests and displays results
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Set content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Parse query parameters
    keyword := r.URL.Query().Get("keyword")

    // Log search for analytics
    logSearch(keyword, r.RemoteAddr)

    // Generate HTML response
    htmlContent := generateHTML(keyword)

    // Write response
    fmt.Fprint(w, htmlContent)
}

// logSearch records search activity for analytics
func logSearch(keyword, remoteAddr string) {
    if keyword == "" {
        return
    }

    analytics.mu.Lock()
    defer analytics.mu.Unlock()

    // Increment keyword count
    analytics.keywords[keyword]++

    // Record search event
    event := SearchEvent{
        Keyword:   keyword,
        Timestamp: time.Now(),
        IPAddress: remoteAddr,
    }
    analytics.history = append(analytics.history, event)

    // Keep history manageable (last 1000 events)
    if len(analytics.history) > 1000 {
        analytics.history = analytics.history[len(analytics.history)-1000:]
    }
}

