    // Add analytics stats if keyword was provided
    if keyword != "" {
        analytics.mu.RLock()
        count := analytics.keywords[keyword]
        totalSearches := len(analytics.history)
        analytics.mu.RUnlock()

        html += `
        <div class="stats">
            <strong>Search Analytics:</strong><br>
            • This keyword has been searched <strong>` + fmt.Sprintf("%d", count) + `</strong> time(s)<br>
