// GetAnalyticsHandler returns analytics data as JSON (optional endpoint)
func GetAnalyticsHandler(w http.ResponseWriter, r *http.Request) {
    analytics.mu.RLock()
    defer analytics.mu.RUnlock()

    data := struct {
        Keywords     map[string]int `json:"keywords"`
        TotalSearches int           `json:"total_searches"`
        RecentEvents []SearchEvent  `json:"recent_events,omitempty"`
    }{
        Keywords:     analytics.keywords,
        TotalSearches: len(analytics.history),
    }

    // Include recent events if requested
    if r.URL.Query().Get("include_history") == "true" {
        // Return last 50 events
        start := len(analytics.history) - 50
        if start < 0 {
            start = 0
        }
        data.RecentEvents = analytics.history[start:]
    }

    w.Header().Set("Content-Type", "application/json")
    json.NewEncoder(w).Encode(data)
}

func main() {
    // Register handlers
    http.HandleFunc("/search", HandleProductSearch)
    http.HandleFunc("/analytics", GetAnalyticsHandler)

    // Root redirects to search with empty keyword
    http.HandleFunc("/", func(w http.ResponseWriter, r *http.Request) {
        http.Redirect(w, r, "/search", http.StatusFound)
    })

    // Start server
    port := ":8080"
    fmt.Printf("Server starting on http://localhost%s\n", port)
    fmt.Println("Endpoints:")
    fmt.Println("  GET /search?keyword=product - Product search")
    fmt.Println("  GET /analytics - Search analytics data")
    fmt.Println("  GET / - Redirects to /search")

    if err := http.ListenAndServe(port, nil); err != nil {
        log.Fatal("Server error: ", err)
    }
}

